import torch, torch.nn as nn

# CNN预测蛋白质二级结构 (H=α-helix, E=β-sheet, C=coil)
class ProteinSSPredictor(nn.Module):
    def __init__(self, num_amino_acids=21, hidden=128, num_classes=3):
        super().__init__()
        self.conv = nn.Conv1d(num_amino_acids, hidden, kernel_size=7, padding=3)
        self.fc = nn.Linear(hidden, num_classes)
    def forward(self, x):
        return self.fc(self.conv(x).mean(dim=-1))

model = ProteinSSPredictor()

import torch.nn as nn

class GeneExpressionGenerator(nn.Module):
    def __init__(self, latent_dim=100, n_genes=5000):
        super().__init__()
        self.model = nn.Sequential(
            nn.Linear(latent_dim + 10, 256),  # +10 for cell type condition
            nn.BatchNorm1d(256), nn.ReLU(),
            nn.Linear(256, 512), nn.BatchNorm1d(512), nn.ReLU(),
            nn.Linear(512, n_genes), nn.ReLU()  # expression must be >= 0
        )

    def forward(self, z, cell_type):
        return self.model(torch.cat([z, cell_type], dim=1))

class GeneExpressionDiscriminator(nn.Module):
    def __init__(self, n_genes=5000):
        super().__init__()
        self.model = nn.Sequential(
            nn.Linear(n_genes + 10, 512), nn.LeakyReLU(0.2),
            nn.Linear(512, 256), nn.LeakyReLU(0.2),
            nn.Linear(256, 1), nn.Sigmoid()
        )

    def forward(self, x, cell_type):
        return self.model(torch.cat([x, cell_type], dim=1))

