import torch
from torch_geometric.nn import GCNConv, global_mean_pool

# 图神经网络预测分子ADMET性质
class MoleculeGCN(torch.nn.Module):
    def __init__(self, num_features, hidden=128):
        super().__init__()
        self.conv1 = GCNConv(num_features, hidden)
        self.conv2 = GCNConv(hidden, hidden)
        self.fc = torch.nn.Linear(hidden, 1)  # 输出: 毒性/活性预测
    def forward(self, data):
        x = self.conv1(data.x, data.edge_index).relu()
        x = self.conv2(x, data.edge_index).relu()
        return self.fc(global_mean_pool(x, data.batch))

